import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Line } from "react-chartjs-2";

// Register chart.js modules (important for v3+)
ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

const ChartArea = ({ chartData, isLoading }) => {
  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-full bg-white rounded-3xl shadow-lg">
        <p className="text-gray-500">Loading chart...</p>
      </div>
    );
  }

  if (!chartData || !chartData.labels?.length) {
    return (
      <div className="flex items-center justify-center h-full bg-white rounded-3xl shadow-lg">
        <p className="text-gray-400">No historical data available</p>
      </div>
    );
  }

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        display: false,
      },
      tooltip: {
        mode: "index",
        intersect: false,
      },
    },
    interaction: {
      mode: "nearest",
      axis: "x",
      intersect: false,
    },
    scales: {
      x: {
        display: true,
        title: {
          display: false,
        },
      },
      y: {
        display: true,
        title: {
          display: false,
        },
      },
    },
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl p-4 h-[400px]">
      <Line data={chartData} options={options} />
    </div>
  );
};

export default ChartArea;
